    if (i < R)
    {
        // 1. Compute Mean
        float sum = 0.0f;
        for (int j = 0; j < C; j++)
            sum += a[i * C + j];
        float mean = sum / C;

        // 2. Compute Variance
        float var = 0.0f;
        for (int j = 0; j < C; j++)
        {
            float diff = a[i * C + j] - mean;
            var += diff * diff;
        }
        float inv_std = 1.0f / sqrtf((var / C) + eps);

        // 3. Normalize
        for (int j = 0; j < C; j++)
        {
            out[i * C + j] = (a[i * C + j] - mean) * inv_std;
        }
    }
}

__global__ void layer_norm_bwd(float *a, float *go, float *ga, int R, int C, float eps)
