        {
            float diff = a[i * C + j] - mean;
            var += diff * diff;
        }
        float inv_std = 1.0f / sqrtf((var / C) + eps);

        // 2. Compute intermediate sums for the gradient
        // dl/dx = (1/C * inv_std) * [ C*dl/dy - sum(dl/dy) - y * sum(dl/dy * y) ]
        float sum_dl_dy = 0.0f;
