            sum_dl_dy_y += dy * y;
        }

        // 3. Final Gradient
        for (int j = 0; j < C; j++)
        {
            float y = (a[i * C + j] - mean) * inv_std;
            float grad = inv_std * (go[i * C + j] - (sum_dl_dy / C) - (y * sum_dl_dy_y / C));
            atomicAdd(&ga[i * C + j], grad);
        }
    }
}
__global__ void layernorm_fwd(float *x, float *gamma, float *beta, float *out, int R, int C, float eps)
{
