        float sq_diff_sum = 0;
        for (int j = 0; j < C; j++)
        {
            float diff = x[i * C + j] - mean;
            sq_diff_sum += diff * diff;
        }
        float var = sq_diff_sum / C;
        float std_inv = 1.0f / sqrtf(var + eps);

        // 3. Normalize and Scale/Shift
