        {
            float x_hat = (x[i * C + j] - mean) * std_inv;
            out[i * C + j] = x_hat * gamma[j] + beta[j];
        }
    }
}

__global__ void layernorm_bwd(float *x, float *gamma, float *go, float *gx, float *gGamma, float *gBeta, int R, int C, float eps)
